//! parity-chunk-vs-single — kernel-only multi-chunk vs single-chunk parity.
//!
//! HYPOTHESIS UNDER TEST
//! ---------------------
//! pneuma-think → fat-station mesh produces gibberish ONLY when the prompt is
//! split across multiple `forward_range_chunk` calls (chunk_size=4). The
//! single-call path is proven correct by `native-pipeline-smoke` (argmax=15
//! with plausible logits on `say hello in 5 words`).
//!
//! THE BIG QUESTION
//! ----------------
//! Does `forward_range_chunk` produce identical residuals for tokens 4..8 when:
//!   PATH A (reference): one call, seq_len=8, start_pos=0, all 8 tokens at once
//!   PATH B (chunked):   call#1 seq_len=4 start_pos=0 (writes KV[0..4]),
//!                       call#2 seq_len=4 start_pos=4 (reads KV[0..4], writes KV[4..8])
//!
//! If A and B match for tokens 4..7, the kernel is innocent and the gibberish
//! lives in the JS Pipeline dispatch (chunks queueing wrong, residuals routed
//! wrong, etc). If they diverge, the multi-call KV-cache attention path has a
//! bug we can bisect.
//!
//! Two pipelines are constructed (independent KV caches) so chunk-1 of PATH B
//! does not corrupt PATH A's state. We use the same hand-rolled token IDs and
//! the same start_pos so any divergence is purely a function of single-call vs
//! split-call dispatch.
//!
//! Usage:
//!   cargo run --release --bin parity-chunk-vs-single -- /tmp/qwen-coder-7b.knot

use std::env;
use std::time::Instant;

use distributed_inference::loader::KnotWeights;
use distributed_inference::NativeLlamaPipeline;

fn cosine(a: &[f32], b: &[f32]) -> f32 {
    let mut dot = 0.0f64;
    let mut na = 0.0f64;
    let mut nb = 0.0f64;
    for i in 0..a.len() {
        let av = a[i] as f64;
        let bv = b[i] as f64;
        dot += av * bv;
        na += av * av;
        nb += bv * bv;
    }
    let denom = na.sqrt() * nb.sqrt();
    if denom == 0.0 {
        return 0.0;
    }
    (dot / denom) as f32
}

fn max_abs_delta(a: &[f32], b: &[f32]) -> f32 {
    let mut m = 0.0f32;
    for i in 0..a.len() {
        let d = (a[i] - b[i]).abs();
        if d > m {
            m = d;
        }
    }
    m
}

fn mean_abs_delta(a: &[f32], b: &[f32]) -> f32 {
    let mut s = 0.0f64;
    for i in 0..a.len() {
        s += (a[i] - b[i]).abs() as f64;
    }
    (s / a.len() as f64) as f32
}

fn finite_stats(name: &str, v: &[f32]) {
    let mut nan = 0usize;
    let mut inf = 0usize;
    let mut lo = f32::INFINITY;
    let mut hi = f32::NEG_INFINITY;
    let mut sum = 0.0f64;
    for &x in v {
        if x.is_nan() {
            nan += 1;
            continue;
        }
        if x.is_infinite() {
            inf += 1;
            continue;
        }
        if x < lo {
            lo = x;
        }
        if x > hi {
            hi = x;
        }
        sum += x as f64;
    }
    let mean = sum / v.len() as f64;
    println!(
        "       [{}] len={} nan={} inf={} range=[{:.4}, {:.4}] mean={:.4}",
        name,
        v.len(),
        nan,
        inf,
        lo,
        hi,
        mean
    );
}

fn run_path_a(
    knot_path: &str,
    tokens: &[u32],
    end_layer: usize,
) -> Result<(Vec<f32>, usize), String> {
    let knot = KnotWeights::load(knot_path)?;
    let hidden_dim = knot.config.as_ref().map(|c| c.hidden_dim).unwrap_or(2048);
    let mut p = NativeLlamaPipeline::from_knot(knot, false, 0.0);
    let emb = p.embed_chunk(tokens, 0)?;
    let seq_len = tokens.len();
    let out = p.forward_range_chunk(&emb, 0, end_layer, 0, seq_len)?;
    Ok((out, hidden_dim))
}

fn run_path_b(
    knot_path: &str,
    tokens: &[u32],
    end_layer: usize,
    chunk_a: usize,
    chunk_b: usize,
) -> Result<(Vec<f32>, usize), String> {
    assert_eq!(
        chunk_a + chunk_b,
        tokens.len(),
        "chunk sizes must sum to total"
    );
    let knot = KnotWeights::load(knot_path)?;
    let hidden_dim = knot.config.as_ref().map(|c| c.hidden_dim).unwrap_or(2048);
    let mut p = NativeLlamaPipeline::from_knot(knot, false, 0.0);
    let emb = p.embed_chunk(tokens, 0)?;

    // Chunk 1: positions 0..chunk_a
    let chunk1 = &emb[0..chunk_a * hidden_dim];
    let _ = p.forward_range_chunk(chunk1, 0, end_layer, 0, chunk_a)?;

    // Chunk 2: positions chunk_a..chunk_a+chunk_b, start_pos=chunk_a
    let chunk2 = &emb[chunk_a * hidden_dim..(chunk_a + chunk_b) * hidden_dim];
    let out2 = p.forward_range_chunk(chunk2, 0, end_layer, chunk_a, chunk_b)?;
    Ok((out2, hidden_dim))
}

fn compare_tail(
    name: &str,
    a_full: &[f32],
    b_chunk2: &[f32],
    hidden_dim: usize,
    tail_count: usize,
    total_a_seq: usize,
) {
    // a_full has total_a_seq * hidden_dim. We compare its last `tail_count`
    // tokens against b_chunk2 (which has tail_count * hidden_dim).
    let start = (total_a_seq - tail_count) * hidden_dim;
    let a_tail = &a_full[start..];
    assert_eq!(a_tail.len(), b_chunk2.len(), "tail/chunk2 size mismatch");
    let cos = cosine(a_tail, b_chunk2);
    let mxa = max_abs_delta(a_tail, b_chunk2);
    let mna = mean_abs_delta(a_tail, b_chunk2);
    println!(
        "       [{}] cos={:.6}  max-abs-delta={:.6}  mean-abs-delta={:.6}",
        name, cos, mxa, mna
    );
    // Per-token breakdown
    for t in 0..tail_count {
        let ta = &a_tail[t * hidden_dim..(t + 1) * hidden_dim];
        let tb = &b_chunk2[t * hidden_dim..(t + 1) * hidden_dim];
        let c = cosine(ta, tb);
        let mx = max_abs_delta(ta, tb);
        let mn = mean_abs_delta(ta, tb);
        println!(
            "         tok[{}] cos={:.6}  max-abs={:.6}  mean-abs={:.6}",
            t, c, mx, mn
        );
    }
}

fn main() -> Result<(), String> {
    let args: Vec<String> = env::args().collect();
    if args.len() < 2 {
        return Err(format!(
            "usage: {} <knot.path>",
            args.first()
                .map(String::as_str)
                .unwrap_or("parity-chunk-vs-single")
        ));
    }
    let knot_path = args[1].clone();

    // 8 valid qwen2 token IDs (vocab=151,936). Same shape pneuma-think uses
    // when it splits a long prompt into chunk_size=4 pieces.
    let tokens: Vec<u32> = vec![1234, 2345, 3456, 4567, 5678, 6789, 7890, 8901];

    println!("============================================================");
    println!(" parity-chunk-vs-single");
    println!("   knot   : {}", knot_path);
    println!("   tokens : {:?}", tokens);
    println!("============================================================");

    // First sanity: confirm config + that the knot loads.
    {
        let knot = KnotWeights::load(&knot_path)?;
        let cfg = knot.config.as_ref().ok_or("no config block in knot")?;
        println!(
            "[meta] hidden={} layers={} heads={} kv={} head_dim={} ffn={} vocab={} rope={}",
            cfg.hidden_dim,
            cfg.num_layers,
            cfg.num_heads,
            cfg.num_kv_heads,
            cfg.head_dim,
            cfg.intermediate_size,
            cfg.vocab_size,
            cfg.rope_theta,
        );
    }
    let total_layers = {
        let knot = KnotWeights::load(&knot_path)?;
        knot.config.as_ref().map(|c| c.num_layers).unwrap_or(28)
    };

    // ---------- Test 1: full-stack (all layers), 4+4 split ----------
    println!(
        "\n----- TEST 1: end_layer={}  4+4 split -----",
        total_layers
    );
    let t = Instant::now();
    let (a, hd) = run_path_a(&knot_path, &tokens, total_layers)?;
    println!(
        "[A] full forward_range_chunk(seq_len=8) ok in {} ms  out={}",
        t.elapsed().as_millis(),
        a.len()
    );
    finite_stats("A", &a);

    let t = Instant::now();
    let (b, _) = run_path_b(&knot_path, &tokens, total_layers, 4, 4)?;
    println!(
        "[B] split forward_range_chunk(4)+forward_range_chunk(4) ok in {} ms  out={}",
        t.elapsed().as_millis(),
        b.len()
    );
    finite_stats("B", &b);

    println!("[T1] tail (tokens 4..7) parity:");
    compare_tail("T1", &a, &b, hd, 4, 8);

    // ---------- Test 2: 2 layers only, 4+4 split ----------
    println!("\n----- TEST 2: end_layer=2  4+4 split (kernel-only, no full stack noise) -----");
    let (a2, _) = run_path_a(&knot_path, &tokens, 2)?;
    finite_stats("A", &a2);
    let (b2, _) = run_path_b(&knot_path, &tokens, 2, 4, 4)?;
    finite_stats("B", &b2);
    println!("[T2] tail (tokens 4..7) parity:");
    compare_tail("T2", &a2, &b2, hd, 4, 8);

    // ---------- Test 3: 1 layer only, 4+4 split ----------
    println!("\n----- TEST 3: end_layer=1  4+4 split -----");
    let (a3, _) = run_path_a(&knot_path, &tokens, 1)?;
    let (b3, _) = run_path_b(&knot_path, &tokens, 1, 4, 4)?;
    println!("[T3] tail (tokens 4..7) parity:");
    compare_tail("T3", &a3, &b3, hd, 4, 8);

    // ---------- Test 4: 1 layer, 2+2 split (4 tokens total) ----------
    println!("\n----- TEST 4: end_layer=1  2+2 split (4 tokens) -----");
    let short_tokens: Vec<u32> = tokens[..4].to_vec();
    let knot = KnotWeights::load(&knot_path)?;
    let mut p_a = NativeLlamaPipeline::from_knot(knot, false, 0.0);
    let emb_a = p_a.embed_chunk(&short_tokens, 0)?;
    let a4 = p_a.forward_range_chunk(&emb_a, 0, 1, 0, 4)?;

    let knot = KnotWeights::load(&knot_path)?;
    let mut p_b = NativeLlamaPipeline::from_knot(knot, false, 0.0);
    let emb_b = p_b.embed_chunk(&short_tokens, 0)?;
    let _ = p_b.forward_range_chunk(&emb_b[..2 * hd], 0, 1, 0, 2)?;
    let b4 = p_b.forward_range_chunk(&emb_b[2 * hd..4 * hd], 0, 1, 2, 2)?;
    println!("[T4] tail (tokens 2..3) parity:");
    compare_tail("T4", &a4, &b4, hd, 2, 4);

    // ---------- Test 5: chunk_size=1 path. seq_len=1 split into 4 calls ----------
    println!("\n----- TEST 5: end_layer=1  1+1+1+1 split (4 tokens) -----");
    let knot = KnotWeights::load(&knot_path)?;
    let mut p_c = NativeLlamaPipeline::from_knot(knot, false, 0.0);
    let emb_c = p_c.embed_chunk(&short_tokens, 0)?;
    let _ = p_c.forward_range_chunk(&emb_c[0..hd], 0, 1, 0, 1)?;
    let _ = p_c.forward_range_chunk(&emb_c[hd..2 * hd], 0, 1, 1, 1)?;
    let _ = p_c.forward_range_chunk(&emb_c[2 * hd..3 * hd], 0, 1, 2, 1)?;
    let c5 = p_c.forward_range_chunk(&emb_c[3 * hd..4 * hd], 0, 1, 3, 1)?;
    println!("[T5] last token (token 3) parity vs A's tail:");
    compare_tail("T5", &a4, &c5, hd, 1, 4);

    // ---------- Test 6: BIG batch — 128-token single call vs 64+64 chunked.
    // Validates the raised fat-station NATIVE_BATCH_CAPACITY=128 prefill chunk:
    // a single forward_range_chunk(seq_len=128) must match a chunked 64+64 run
    // bit-exactly, exercising model.rs BATCH_CAPACITY=128 buffers at full size
    // (the gemma4 history shows seq>8 can surface slice/OOB bugs).
    println!(
        "\n----- TEST 6: end_layer={}  128-tok single vs 64+64 split -----",
        total_layers
    );
    let big_tokens: Vec<u32> = (0..128u32).map(|i| (i * 137 + 1234) % 31000).collect();
    let (a6, hd6) = run_path_a(&knot_path, &big_tokens, total_layers)?;
    println!("[A] forward_range_chunk(seq_len=128) ok, out={}", a6.len());
    finite_stats("A", &a6);
    let (b6, _) = run_path_b(&knot_path, &big_tokens, total_layers, 64, 64)?;
    println!(
        "[B] forward_range_chunk(64)+forward_range_chunk(64) ok, out={}",
        b6.len()
    );
    finite_stats("B", &b6);
    println!("[T6] tail (tokens 64..127) parity:");
    compare_tail("T6", &a6, &b6, hd6, 64, 128);

    println!("\n============================================================");
    println!(" parity-chunk-vs-single  DONE");
    println!("============================================================");
    Ok(())
}
